@dataclass
class Vector3:
    x: float = 0.0
    y: float = 0.0
    z: float = 0.0

    def distance_to(self, other: 'Vector3') -> float:
        return math.sqrt(
            (self.x - other.x) ** 2 +
            (self.y - other.y) ** 2 +
            (self.z - other.z) ** 2
        )

    def to_dict(self) -> dict:
        return {"x": self.x, "y": self.y, "z": self.z}

    @staticmethod
    def from_dict(d: dict) -> 'Vector3':
        return Vector3(d.get("x", 0), d.get("y", 0), d.get("z", 0))


@dataclass
class Obstacle:
    """Represents a wall or obstacle for line-of-sight checks."""
    min_corner: Vector3
    max_corner: Vector3
    obstacle_type: str = "wall"  # wall, building, rock

    def intersects_ray(self, origin: Vector3, direction: Vector3, max_dist: float) -> bool:
        """AABB ray intersection test."""
        t_min = 0.0
        t_max = max_dist

        for axis in ['x', 'y', 'z']:
            o = getattr(origin, axis)
            d = getattr(direction, axis)
            min_val = getattr(self.min_corner, axis)
            max_val = getattr(self.max_corner, axis)

            if abs(d) < 1e-8:
                if o < min_val or o > max_val:
                    return False
            else:
                t1 = (min_val - o) / d
                t2 = (max_val - o) / d
                if t1 > t2:
                    t1, t2 = t2, t1
                t_min = max(t_min, t1)
                t_max = min(t_max, t2)
                if t_min > t_max:
                    return False
        return True


