@dataclass
class Zone:
    center: Vector3
    radius: float
    damage_per_tick: int
    next_center: Optional[Vector3] = None
    next_radius: float = 0.0
    shrink_start_time: float = 0.0
    shrink_duration: float = 60.0

    def get_current_radius(self, current_time: float) -> float:
        if self.next_center is None:
            return self.radius
        elapsed = current_time - self.shrink_start_time
        progress = min(1.0, elapsed / self.shrink_duration)
        return self.radius + (self.next_radius - self.radius) * progress

    def get_current_center(self, current_time: float) -> Vector3:
        if self.next_center is None:
            return self.center
        elapsed = current_time - self.shrink_start_time
        progress = min(1.0, elapsed / self.shrink_duration)
        return Vector3(
            self.center.x + (self.next_center.x - self.center.x) * progress,
            self.center.y + (self.next_center.y - self.center.y) * progress,
            self.center.z + (self.next_center.z - self.center.z) * progress,
        )

    def is_inside(self, pos: Vector3, current_time: float) -> bool:
        center = self.get_current_center(current_time)
        radius = self.get_current_radius(current_time)
        dx = pos.x - center.x
        dz = pos.z - center.z
        return (dx * dx + dz * dz) <= radius * radius


class VisibilitySystem:
    """
    SERVER-SIDE visibility determination.
    This is the anti-wallhack system: the server only sends position data
    for players that the receiving client SHOULD be able to see.
    """

    # Maximum distance at which any player data is sent
    MAX_RELEVANCE_DISTANCE = 300.0
    # Distance for full visibility (close quarters)
    CLOSE_RANGE = 15.0
    # Distance for audio-only hints
    AUDIO_RANGE = 50.0
    # Field of view half-angle for extended visibility
    FOV_HALF_ANGLE = 75.0  # degrees
    # Maximum line-of-sight check distance
    LOS_MAX_DISTANCE = 250.0

    def __init__(self, obstacles: List[Obstacle]):
        self.obstacles = obstacles
        # Spatial grid for efficient obstacle lookups
        self.grid_size = 50.0
        self.obstacle_grid: Dict[Tuple[int, int], List[Obstacle]] = {}
        self._build_obstacle_grid()

    def _build_obstacle_grid(self):
        for obs in self.obstacles:
            min_gx = int(obs.min_corner.x // self.grid_size)
            max_gx = int(obs.max_corner.x // self.grid_size)
            min_gz = int(obs.min_corner.z // self.grid_size)
            max_gz = int(obs.max_corner.z // self.grid_size)
            for gx in range(min_gx, max_gx + 1):
                for gz in range(min_gz, max_gz + 1):
                    key = (gx, gz)
                    if key not in self.obstacle_grid:
                        self.obstacle_grid[key] = []
                    self.obstacle_grid[key].append(obs)

    def _get_relevant_obstacles(self, p1: Vector3, p2: Vector3) -> List[Obstacle]:
        """Get obstacles that could be between two points."""
        min_x = min(p1.x, p2.x)
        max_x = max(p1.x, p2.x)
        min_z = min(p1.z, p2.z)
        max_z = max(p1.z, p2.z)

        min_gx = int(min_x // self.grid_size) - 1
        max_gx = int(max_x // self.grid_size) + 1
        min_gz = int(min_z // self.grid_size) - 1
        max_gz = int(max_z // self.grid_size) + 1

        relevant = set()
        for gx in range(min_gx, max_gx + 1):
            for gz in range(min_gz, max_gz + 1):
                for obs in self.obstacle_grid.get((gx, gz), []):
                    relevant.add(id(obs))

        # Return actual obstacle objects
        seen = set()
        result = []
        for gx in range(min_gx, max_gx + 1):
            for gz in range(min_gz, max_gz + 1):
                for obs in self.obstacle_grid.get((gx, gz), []):
                    oid = id(obs)
                    if oid not in seen:
                        seen.add(oid)
                        result.append(obs)
        return result

    def has_line_of_sight(self, from_pos: Vector3, to_pos: Vector3) -> bool:
        """Check if there's a clear line of sight between two positions."""
        dist = from_pos.distance_to(to_pos)
        if dist < 0.01:
            return True
        if dist > self.LOS_MAX_DISTANCE:
            return False

        direction = Vector3(
            (to_pos.x - from_pos.x) / dist,
            (to_pos.y - from_pos.y) / dist,
            (to_pos.z - from_pos.z) / dist,
        )

        relevant_obstacles = self._get_relevant_obstacles(from_pos, to_pos)
        for obstacle in relevant_obstacles:
            if obstacle.intersects_ray(from_pos, direction, dist):
                return False
        return True

    def determine_visibility(
        self, viewer: Player, target: Player, teammates: Set[str]
    ) -> str:
        """
        Determine what level of information about 'target' should be sent to 'viewer'.

        Returns:
            'full' - Send complete position and state
            'audio' - Send proximity hint only (no position)
            'minimal' - Send only alive/dead status
            'none' - Send nothing
        """
        if not target.alive:
            return "minimal"

        if not viewer.alive:
            # Dead players in spectate mode get full view of their killer or teammates
            if target.team_id and target.team_id == viewer.team_id:
                return "full"
            return "minimal"

        # Teammates always get full visibility
        if target.team_id and target.team_id == viewer.team_id:
            return "full"

        distance = viewer.position.distance_to(target.position)

        # Beyond max relevance - no data at all
        if distance > self.MAX_RELEVANCE_DISTANCE:
            return "none"

        # Very close range - always visible (footstep sounds, etc.)
        if distance <= self.CLOSE_RANGE:
            return "full"

        # Check line of sight from server's authoritative positions
        # Use slightly elevated position (eye height)
        viewer_eye = Vector3(viewer.position.x, viewer.position.y + 1.6, viewer.position.z)
        # Check against multiple points on target (head, torso, feet)
        target_points = [
            Vector3(target.position.x, target.position.y + 1.6, target.position.z),  # head
            Vector3(target.position.x, target.position.y + 0.9, target.position.z),  # torso
            Vector3(target.position.x, target.position.y + 0.1, target.position.z),  # feet
        ]

        has_los = any(
            self.has_line_of_sight(viewer_eye, tp) for tp in target_points
        )

        if has_los and distance <= self.LOS_MAX_DISTANCE:
            return "full"

        # Audio range - can hear but not see
        if distance <= self.AUDIO_RANGE:
            return "audio"

        # Player is in relevance range but not visible
        return "none"


class AntiCheat:
    """Server-side anti-cheat validation."""

    MAX_SPEED = 12.0  # units per second (sprinting)
    MAX_SPEED_VEHICLE = 40.0
    TELEPORT_THRESHOLD = 20.0  # max distance in one tick
    MAX_FIRE_RATE = {
        "pistol": 0.3,
        "rifle": 0.1,
        "shotgun": 0.8,
        "sniper": 1.5,
        "smg": 0.075,
    }
    POSITION_HISTORY_SIZE = 60
    MAX_VIOLATIONS_BEFORE_KICK = 10

    @staticmethod
    def validate_movement(player: Player, new_pos: Vector3, dt: float) -> Tuple[bool, str]:
        """Validate a movement update from client."""
        if dt <= 0:
            return False, "invalid_dt"

        distance = player.position.distance_to(new_pos)
        speed = distance / dt

        # Check for teleportation
        if distance > AntiCheat.TELEPORT_THRESHOLD:
            return False, "teleport_detected"

        # Check speed
        max_allowed = AntiCheat.MAX_SPEED * 1.5  # 50% tolerance for lag
        if speed > max_allowed:
            return False, f"speed_hack: {speed:.1f} > {max_allowed:.1f}"

        # Check vertical movement (no fly hack)
        vertical_speed = abs(new_pos.y - player.position.y) / dt
        if vertical_speed > 20.0 and new_pos.y > player.position.y:
            return False, "fly_hack_detected"

        return True, "ok"

    @staticmethod
    def validate_shot(player: Player, weapon: str, current_time: float) -> Tuple[bool, str]:
        """Validate fire rate."""
        min_interval = AntiCheat.MAX_FIRE_RATE.get(weapon, 0.1)
        elapsed = current_time - player.last_shot_time
        if elapsed < min_interval * 0.8:  # 20% tolerance
            return False, "fire_rate_exceeded"
        return True, "ok"

    @staticmethod
    def validate_damage(
        attacker: Player, victim: Player, weapon: str, claimed_damage: int
    ) -> int:
        """Validate and cap damage values."""
        max_damages = {
            "pistol": 35,
            "rifle": 40,
            "shotgun": 120,  # all pellets
            "sniper": 110,
            "smg": 25,
            "fists": 15,
        }
        max_dmg = max_damages.get(weapon, 50)
        return min(claimed_damage, max_dmg)

    @staticmethod
    def record_position(player: Player, current_time: float):
        """Record position for pattern analysis."""
        player.position_history.append((current_time, Vector3(
            player.position.x, player.position.y, player.position.z
        )))
        if len(player.position_history) > AntiCheat.POSITION_HISTORY_SIZE:
            player.position_history.pop(0)


class BattleRoyaleServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 8765):
        self.host = host
        self.port = port
        self.players: Dict[str, Player] = {}
        self.projectiles: Dict[str, Projectile] = {}
        self.loot_items: Dict[str, LootItem] = {}
        self.game_phase = GamePhase.LOBBY
        self.tick_rate = 20  # Server ticks per second
        self.tick_interval = 1.0 / self.tick_rate
        self.current_tick = 0
        self.game_start_time = 0.0
        self.max_players = 100
        self.min_players_to_start = 2

        # Map configuration
        self.map_size = 2000.0
        self.obstacles: List[Obstacle] = []
        self._generate_map()

        # Zone configuration
        self.zone = Zone(
            center=Vector3(self.map_size / 2, 0, self.map_size / 2),
            radius=self.map_size / 2,
            damage_per_tick=1,
        )
        self.zone_phase = 0
        self.zone_configs = [
            {"radius": 800, "damage": 1, "delay": 120, "shrink": 60},
            {"radius": 500, "damage": 2, "delay": 90, "shrink": 50},
            {"radius": 300, "damage": 5, "delay": 60, "shrink": 40},
            {"radius": 150, "damage": 8, "delay": 45, "shrink": 30},
            {"radius": 50, "damage": 10, "delay": 30, "shrink": 20},
            {"radius": 10, "damage": 15, "delay": 15, "shrink": 10},
        ]
        self.next_zone_time = 0.0

        # Visibility system - THE anti-wallhack core
        self.visibility_system = VisibilitySystem(self.obstacles)

        # Event log for replay/audit
        self.event_log: List[dict] = []

        # Auth tokens
        self.valid_tokens: Dict[str, str] = {}  # token -> username

        print(f"[SERVER] Battle Royale Server initialized")
        print(f"[SERVER] Anti-wallhack: Server-side visibility filtering ENABLED")
        print(f"[SERVER] Tick rate: {self.tick_rate} Hz")

    def _generate_map(self):
        """Generate map obstacles for line-of-sight calculations."""
        import random
        random.seed(42)  # Deterministic map

        # Generate buildings
        for i in range(50):
            x = random.uniform(100, self.map_size - 100)
            z = random.uniform(100, self.map_size - 100)
            w = random.uniform(10, 40)
            h = random.uniform(5, 20)
            d = random.uniform(10, 40)
            self.obstacles.append(Obstacle(
                min_corner=Vector3(x, 0, z),
                max_corner=Vector3(x + w, h, z + d),
                obstacle_type="building"
            ))

        # Generate walls
        for i in range(100):
            x = random.uniform(50, self.map_size - 50)
            z = random.uniform(50, self.map_size - 50)
            if random.random() > 0.5:
                w, d = random.uniform(15, 30), 1.0
            else:
                w, d = 1.0, random.uniform(15, 30)
            h = random.uniform(2, 5)
            self.obstacles.append(Obstacle(
                min_corner=Vector3(x, 0, z),
                max_corner=Vector3(x + w, h, z + d),
                obstacle_type="wall"
            ))

        # Generate rocks/cover
        for i in range(200):
            x = random.uniform(20, self.map_size - 20)
            z = random.uniform(20, self.map_size - 20)
            s = random.uniform(1, 5)
            h = random.uniform(1, 3)
            self.obstacles.append(Obstacle(
                min_corner=Vector3(x, 0, z),
                max_corner=Vector3(x + s, h, z + s),
                obstacle_type="rock"
            ))

        # Generate loot
        for i in range(500):
            x = random.uniform(50, self.map_size - 50)
            z = random.uniform(50, self.map_size - 50)
            item_types = ["rifle", "pistol", "shotgun", "sniper", "smg",
                          "ammo_light", "ammo_heavy", "ammo_shells",
                          "shield_small", "shield_large", "medkit", "bandage"]
            item_type = random.choice(item_types)
            self.loot_items[f"loot_{i}"] = LootItem(
                item_id=f"loot_{i}",
                item_type=item_type,
                position=Vector3(x, 0, z),
                quantity=random.randint(1, 3) if "ammo" in item_type else 1,
            )

        print(f"[MAP] Generated {len(self.obstacles)} obstacles, {len(self.loot_items)} loot items")

    def generate_auth_token(self, username: str) -> str:
        """Generate authentication token for a player."""
        token = secrets.token_hex(32)
        self.valid_tokens[token] = username
        return token

    async def handle_connection(self, websocket, path=None):
        """Handle a new WebSocket connection."""
        player_id = None
        try:
            # Authentication handshake
            auth_msg = await asyncio.wait_for(websocket.recv(), timeout=10.0)
            auth_data = json.loads(auth_msg)

            if auth_data.get("type") != "auth":
                await websocket.send(json.dumps({"type": "error", "message": "auth_required"}))
                return

            token = auth_data.get("token", "")
            username = self.valid_tokens.get(token)

            if not username:
                # For testing, auto-register
                username = auth_data.get("username", f"Player_{secrets.token_hex(4)}")
                token = self.generate_auth_token(username)

            if len(self.players) >= self.max_players:
                await websocket.send(json.dumps({"type": "error", "message": "server_full"}))
                return

            player_id = str(uuid.uuid4())[:8]
            import random
            player = Player(
                player_id=player_id,
                username=username,
                websocket=websocket,
                position=Vector3(
                    random.uniform(100, self.map_size - 100),
                    0,
                    random.uniform(100, self.map_size - 100),
                ),
                auth_token=token,
            )
            self.players[player_id] = player

            # Send welcome message with player ID and map data
            await websocket.send(json.dumps({
                "type": "welcome",
                "player_id": player_id,
                "username": username,
                "map_size": self.map_size,
                "tick_rate": self.tick_rate,
                "obstacle_count": len(self.obstacles),
                "game_phase": self.game_phase.value,
                "server_info": {
                    "anti_wallhack": "server_side_visibility",
                    "anti_cheat": "server_authoritative",
                },
            }))

            # Send obstacle data (client needs this for rendering, not for visibility)
            obstacle_data = []
            for obs in self.obstacles:
                obstacle_data.append({
                    "min": obs.min_corner.to_dict(),
                    "max": obs.max_corner.to_dict(),
                    "type": obs.obstacle_type,
                })
            await websocket.send(json.dumps({
                "type": "map_data",
                "obstacles": obstacle_data,
            }))

            self._log_event("player_connected", {"player_id": player_id, "username": username})
            print(f"[CONNECT] {username} ({player_id}) connected. Players: {len(self.players)}")

            await self._broadcast_player_list()

            # Check if we should start the game
            if (self.game_phase == GamePhase.LOBBY and
                    len(self.players) >= self.min_players_to_start):
                asyncio.ensure_future(self._start_countdown())

            # Main message loop
            async for message in websocket:
                await self._handle_message(player_id, message)

        except websockets.exceptions.ConnectionClosed:
            pass
        except asyncio.TimeoutError:
            pass
        except Exception as e:
            print(f"[ERROR] Connection error for {player_id}: {e}")
        finally:
            if player_id and player_id in self.players:
                player = self.players[player_id]
                print(f"[DISCONNECT] {player.username} ({player_id}) disconnected")
                player.alive = False
                self._log_event("player_disconnected", {"player_id": player_id})
                del self.players[player_id]
                await self._broadcast_player_list()
                await self._check_win_condition()

    async def _handle_message(self, player_id: str, raw_message: str):
        """Process a message from a client."""
        try:
            data = json.loads(raw_message)
        except json.JSONDecodeError:
            return

        player = self.players.get(player_id)
        if not player:
            return

        msg_type = data.get("type")
        current_time = time.time()

        if msg_type == "move":
            await self._handle_move(player, data, current_time)
        elif msg_type == "shoot":
            await self._handle_shoot(player, data, current_time)
        elif msg_type == "pickup":
            await self._handle_pickup(player, data)
        elif msg_type == "use_item":
            await self._handle_use_item(player, data)
        elif msg_type == "ping":
            await player.websocket.send(json.dumps({
                "type": "pong",
                "server_time": current_time,
                "client_time": data.get("client_time", 0),
            }))

    async def _handle_move(self, player: Player, data: dict, current_time: float):
        """Handle movement input - SERVER AUTHORITATIVE."""
        if not player.alive:
            return

        new_pos = Vector3.from_dict(data.get("position", {}))
        rotation = data.get("rotation", player.rotation)
        input_seq = data.get("seq", 0)

        dt = current_time - player.last_position_update if player.last_position_update > 0 else self.tick_interval
        dt = max(dt, 0.001)

        # Anti-cheat: Validate movement
        valid, reason = AntiCheat.validate_movement(player, new_pos, dt)

        if not valid:
            player.violation_count += 1
            player.speed_violations += 1
            self._log_event("cheat_violation", {
                "player_id": player.player_id,
                "type": "movement",
                "reason": reason,
                "violations": player.violation_count,
            })
            print(f"[ANTICHEAT] {player.username}: {reason} (violations: {player.violation_count})")

            if player.violation_count >= AntiCheat.MAX_VIOLATIONS_BEFORE_KICK:
                await self._kick_player(player, "Too many anti-cheat violations")
                return

            # Reject movement - send correction
            await player.websocket.send(json.dumps({
                "type": "position_correction",
                "position": player.position.to_dict(),
                "seq": input_seq,
                "reason": "server_rejected",
            }))
            return

        # Clamp to map bounds
        new_pos.x = max(0, min(self.map_size, new_pos.x))
        new_pos.z = max(0, min(self.map_size, new_pos.z))
        new_pos.y = max(0, new_pos.y)

        # Check collision with obstacles (simple AABB)
        collision = False
        for obs in self.obstacles:
            if (obs.min_corner.x <= new_pos.x <= obs.max_corner.x and
                    obs.min_corner.z <= new_pos.z <= obs.max_corner.z and
                    obs.min_corner.y <= new_pos.y <= obs.max_corner.y):
                collision = True
                break

        if collision:
            # Reject - keep old position
            await player.websocket.send(json.dumps({
                "type": "position_correction",
                "position": player.position.to_dict(),
                "seq": input_seq,
                "reason": "collision",
            }))
            return

        # Accept movement
        player.position = new_pos
        player.rotation = rotation
        player.last_input_seq = input_seq
        player.last_position_update = current_time
        AntiCheat.record_position(player, current_time)

    async def _handle_shoot(self, player: Player, data: dict, current_time: float):
        """Handle shooting - SERVER AUTHORITATIVE hit detection."""
        if not player.alive:
            return

        weapon = player.equipped_weapon
        if weapon == "fists":
            return

        # Anti-cheat: Validate fire rate
        valid, reason = AntiCheat.validate_shot(player, weapon, current_time)
        if not valid:
            player.violation_count += 1
            self._log_event("cheat_violation", {
                "player_id": player.player_id,
                "type": "fire_rate",
                "reason": reason,
            })
            return

        player.last_shot_time = current_time

        # Server-side hit detection (hitscan weapons)
        target_id = data.get("target_id")
        aim_direction = Vector3.from_dict(data.get("direction", {"x": 0, "y": 0, "z": 1}))

        # Normalize direction
        mag = math.sqrt(aim_direction.x ** 2 + aim_direction.y ** 2 + aim_direction.z ** 2)
        if mag > 0.01:
            aim_direction.x /= mag
            aim_direction.y /= mag
            aim_direction.z /= mag

        weapon_ranges = {
            "pistol": 80, "rifle": 150, "shotgun": 20,
            "sniper": 300, "smg": 60,
        }
        weapon_damages = {
            "pistol": 25, "rifle": 30, "shotgun": 100,
            "sniper": 100, "smg": 18,
        }

        max_range = weapon_ranges.get(weapon, 50)
        base_damage = weapon_damages.get(weapon, 20)

        # Server performs the raycast
        shooter_eye = Vector3(
            player.position.x,
            player.position.y + 1.6,
            player.position.z,
        )

        hit_player = None
        hit_distance = max_range

        for pid, target in self.players.items():
            if pid == player.player_id or not target.alive:
                continue
            if target.team_id and target.team_id == player.team_id:
                continue

            # Simple sphere-ray intersection for hit detection
            dist = self._ray_sphere_intersect(
                shooter_eye, aim_direction, target.position, radius=0.5
            )
            if dist is not None and dist < hit_distance:
                # Verify line of sight from server
                if self.visibility_system.has_line_of_sight(shooter_eye, target.position):
                    hit_player = target
                    hit_distance = dist

        # Broadcast shot event (muzzle flash, sound) to nearby visible players
        shot_event = {
            "type": "shot_fired",
            "shooter_id": player.player_id,
            "weapon": weapon,
            "position": player.position.to_dict(),
            "direction": aim_direction.to_dict(),
        }

        for pid, other in self.players.items():
            if pid == player.player_id:
                continue
            vis = self.visibility_system.determine_visibility(other, player, self._get_teammates(other))
            if vis == "full":
                try:
                    await other.websocket.send(json.dumps(shot_event))
                except:
                    pass
            elif vis == "audio":
                try:
                    await other.websocket.send(json.dumps({
                        "type": "shot_heard",
                        "weapon": weapon,
                        "distance": other.position.distance_to(player.position),
                    }))
                except:
                    pass

        if hit_player:
            damage = AntiCheat.validate_damage(player, hit_player, weapon, base_damage)
            await self._apply_damage(hit_player, damage, player)

            # Confirm hit to shooter
            await player.websocket.send(json.dumps({
                "type": "hit_confirm",
                "target_id": hit_player.player_id,
                "damage": damage,
                "weapon": weapon,
            }))

    def _ray_sphere_intersect(
        self, origin: Vector3, direction: Vector3, center: Vector3, radius: float
    ) -> Optional[float]:
        """Ray-sphere intersection test."""
        oc = Vector3(
            origin.x - center.x,
            origin.y - center.y,
            origin.z - center.z,
        )
        a = direction.x ** 2 + direction.y ** 2 + direction.z ** 2
        b = 2.0 * (oc.x * direction.x + oc.y * direction.y + oc.z * direction.z)
        c = oc.x ** 2 + oc.y ** 2 + oc.z ** 2 - radius ** 2
        discriminant = b * b - 4 * a * c

        if discriminant < 0:
            return None

        t = (-b - math.sqrt(discriminant)) / (2 * a)
        if t < 0:
            t = (-b + math.sqrt(discriminant)) / (2 * a)
        if t < 0:
            return None
        return t

    async def _apply_damage(self, victim: Player, damage: int, attacker: Player):
        """Apply damage to a player."""
        # Shield absorbs first
        shield_damage = min(victim.shield, damage)
        victim.shield -= shield_damage
        remaining = damage - shield_damage
        victim.health -= remaining

        if victim.health <= 0:
            victim.health = 0
            victim.alive = False
            attacker.kills += 1

            kill_event = {
                "type": "player_killed",
                "victim_id": victim.player_id,
                "victim_name": victim.username,
                "killer_id": attacker.player_id,
                "killer_name": attacker.username,
                "weapon": attacker.equipped_weapon,
            }

            self._log_event("kill", kill_event)
            print(f"[KILL] {attacker.username} eliminated {victim.username}")

            # Broadcast kill to all players (this is public info)
            await self._broadcast(kill_event)

            # Drop victim's loot
            await self._drop_loot(victim)

            await self._check_win_condition()
        else:
            # Notify victim of damage
            try:
                await victim.websocket.send(json.dumps({
                    "type": "damage_taken",
                    "damage": damage,
                    "health": victim.health,
                    "shield": victim.shield,
                    "attacker_direction": self._get_direction_hint(victim, attacker),
                }))
            except:
                pass

    def _get_direction_hint(self, victim: Player, attacker: Player) -> float:
        """Get direction angle from victim to attacker (for damage indicator)."""
        dx = attacker.position.x - victim.position.x
        dz = attacker.position.z - victim.position.z
        return math.degrees(math.atan2(dx, dz))

    async def _handle_pickup(self, player: Player, data: dict):
        """Handle item pickup."""
        if not player.alive:
            return

        item_id = data.get("item_id")
        item = self.loot_items.get(item_id)

        if not item or item.picked_up:
            return

        # Verify proximity
        if player.position.distance_to(item.position) > 5.0:
            return

        item.picked_up = True

        if item.item_type in ("rifle", "pistol", "shotgun", "sniper", "smg"):
            player.equipped_weapon = item.item_type
            player.inventory.append(item.item_type)
        elif "ammo" in item.item_type:
            ammo_type = item.item_type.replace("ammo_", "")
            player.ammo[ammo_type] = player.ammo.get(ammo_type, 0) + item.quantity * 30
        elif item.item_type == "shield_small":
            player.shield = min(100, player.shield + 25)
        elif item.item_type == "shield_large":
            player.shield = min(100, player.shield + 50)
        elif item.item_type == "medkit":
            player.health = 100
        elif item.item_type == "bandage":
            player.health = min(75, player.health + 15)

        await player.websocket.send(json.dumps({
            "type": "pickup_confirm",
            "item_id": item_id,
            "item_type": item.item_type,
            "health": player.health,
            "shield": player.shield,
            "weapon": player.equipped_weapon,
        }))

        # Notify nearby players the item was picked up
        for pid, other in self.players.items():
            if pid == player.player_id:
                continue
            if other.position.distance_to(item.position) < 50:
                try:
                    await other.websocket.send(json.dumps({
                        "type": "item_picked_up",
                        "item_id": item_id,
                    }))
                except:
                    pass

    async def _handle_use_item(self, player: Player, data: dict):
        """Handle using an inventory item."""
        if not player.alive:
            return

        item_type = data.get("item_type")
        if item_type in player.inventory:
            if item_type in ("rifle", "pistol", "shotgun", "sniper", "smg"):
                player.equipped_weapon = item_type

            await player.websocket.send(json.dumps({
                "type": "item_used",
                "item_type": item_type,
                "weapon": player.equipped_weapon,
            }))

    async def _drop_loot(self, player: Player):
        """Drop a player's inventory as loot."""
        import random
        for i, item_type in enumerate(player.inventory):
            offset = Vector3(
                random.uniform(-3, 3), 0, random.uniform(-3, 3)
            )
            item_id = f"drop_{player.player_id}_{i}"
            self.loot_items[item_id] = LootItem(
                item_id=item_id,
                item_type=item_type,
                position=Vector3(
                    player.position.x + offset.x,
                    0,
                    player.position.z + offset.z,
                ),
            )

    def _get_teammates(self, player: Player) -> Set[str]:
        """Get set of teammate player IDs."""
        if not player.team_id:
            return set()
        return {
            pid for pid, p in self.players.items()
            if p.team_id == player.team_id and pid != player.player_id
        }

    async def _start_countdown(self):
        """Start game countdown."""
        if self.game_phase != GamePhase.LOBBY:
            return

        print("[GAME] Starting countdown...")
        await self._broadcast({"type": "countdown", "seconds": 10})
        await asyncio.sleep(10)

        if len(self.players) >= self.min_players_to_start:
            await self._start_game()

    async def _start_game(self):
        """Start the game."""
        self.game_phase = GamePhase.PLAYING
        self.game_start_time = time.time()
        self.next_zone_time = self.game_start_time + self.zone_configs[0]["delay"]

        # Spawn players at random positions
        import random
        for player in self.players.values():
            player.position = Vector3(
                random.uniform(200, self.map_size - 200),
                0,
                random.uniform(200, self.map_size - 200),
            )
            player.alive = True
            player.health = 100
            player.shield = 0

        await self._broadcast({
            "type": "game_start",
            "player_count": len(self.players),
            "zone": {
                "center": self.zone.center.to_dict(),
                "radius": self.zone.radius,
            },
        })

        self._log_event("game_start", {"player_count": len(self.players)})
        print(f"[GAME] Game started with {len(self.players)} players!")

    async def _check_win_condition(self):
        """Check if the game has been won."""
        if self.game_phase != GamePhase.PLAYING:
            return

        alive_players = [p for p in self.players.values() if p.alive]
        alive_teams = set()
        for p in alive_players:
            alive_teams.add(p.team_id or p.player_id)

        if len(alive_teams) <= 1:
            self.game_phase = GamePhase.ENDED
            winner = alive_players[0] if alive_players else None
            win_msg = {
                "type": "game_over",
                "winner_id": winner.player_id if winner else None,
                "winner_name": winner.username if winner else "Nobody",
            }
            await self._broadcast(win_msg)
            self._log_event("game_over", win_msg)
            print(f"[GAME] Game over! Winner: {winner.username if winner else 'Nobody'}")

    async def _kick_player(self, player: Player, reason: str):
        """Kick a player from the server."""
        print(f"[KICK] {player.username}: {reason}")
        self._log_event("player_kicked", {
            "player_id": player.player_id,
            "reason": reason,
            "violations": player.violation_count,
        })
        try:
            await player.websocket.send(json.dumps({
                "type": "kicked",
                "reason": reason,
            }))
            await player.websocket.close()
        except:
            pass

    async def game_loop(self):
        """Main server game loop."""
        print("[SERVER] Game loop started")
        last_tick = time.time()

        while True:
            current_time = time.time()
            dt = current_time - last_tick

            if dt >= self.tick_interval:
                last_tick = current_time
                self.current_tick += 1

                if self.game_phase == GamePhase.PLAYING:
                    # Update zone
                    await self._update_zone(current_time)

                    # Apply zone damage
                    await self._apply_zone_damage(current_time)

                # Send visibility-filtered state to each player
                await self._send_game_state(current_time)

            # Small sleep to prevent CPU spinning
            await asyncio.sleep(0.001)

    async def _update_zone(self, current_time: float):
        """Update the storm zone."""
        if current_time >= self.next_zone_time and self.zone_phase < len(self.zone_configs):
            config = self.zone_configs[self.zone_phase]

            import random
            # New zone center (within current zone)
            angle = random.uniform(0, 2 * math.pi)
            max_offset = self.zone.radius - config["radius"]
            offset = random.uniform(0, max_offset * 0.5)
            new_center = Vector3(
                self.zone.center.x + math.cos(angle) * offset,
                0,
                self.zone.center.z + math.sin(angle) * offset,
            )

            self.zone.next_center = new_center
            self.zone.next_radius = config["radius"]
            self.zone.damage_per_tick = config["damage"]
            self.zone.shrink_start_time = current_time
            self.zone.shrink_duration = config["shrink"]

            self.next_zone_time = current_time + config["delay"] + config["shrink"]
            self.zone_phase += 1

            await self._broadcast({
                "type": "zone_update",
                "current_center": self.zone.center.to_dict(),
                "current_radius": self.zone.radius,
                "next_center": new_center.to_dict(),
                "next_radius": config["radius"],
                "shrink_duration": config["shrink"],
                "damage": config["damage"],
            })

            print(f"[ZONE] Phase {self.zone_phase}: radius -> {config['radius']}")

        # Finalize zone shrink
        if self.zone.next_center:
            progress = (current_time - self.zone.shrink_start_time) / self.zone.shrink_duration
            if progress >= 1.0:
                self.zone.center = self.zone.next_center
                self.zone.radius = self.zone.next_radius
                self.zone.next_center = None

    async def _apply_zone_damage(self, current_time: float):
        """Apply damage to players outside the zone."""
        for player in self.players.values():
            if not player.alive:
                continue
            if not self.zone.is_inside(player.position, current_time):
                player.health -= self.zone.damage_per_tick
                if player.health <= 0:
                    player.health = 0
                    player.alive = False
                    await self._broadcast({
                        "type": "player_killed",
                        "victim_id": player.player_id,
                        "victim_name": player.username,
                        "killer_id": "zone",
                        "killer_name": "The Storm",
                        "weapon": "zone",
                    })
                    print(f"[ZONE] {player.username} eliminated by the storm")
                    await self._check_win_condition()
                else:
                    try:
                        await player.websocket.send(json.dumps({
                            "type": "zone_damage",
                            "damage": self.zone.damage_per_tick,
                            "health": player.health,
                        }))
                    except:
                        pass

    async def _send_game_state(self, current_time: float):
        """
        Send VISIBILITY-FILTERED game state to each player.

        THIS IS THE CORE ANTI-WALLHACK MECHANISM:
        Each player only receives position data for other players
        that the server determines they should be able to see.
        """
        # Pre-compute teammate sets
        team_cache: Dict[str, Set[str]] = {}

        for player_id, player in self.players.items():
            if player.team_id:
                if player.team_id not in team_cache:
                    team_cache[player.team_id] = set()
                team_cache[player.team_id].add(player_id)

        for viewer_id, viewer in list(self.players.items()):
            teammates = team_cache.get(viewer.team_id, set()) if viewer.team_id else set()

            visible_players = []
            audio_players = []
            minimal_players = []

            for target_id, target in self.players.items():
                if target_id == viewer_id:
                    continue

                # SERVER determines visibility - client cannot override this
                visibility = self.visibility_system.determine_visibility(
                    viewer, target, teammates
                )

                if visibility == "full":
                    visible_players.append(target.to_public_dict())
                elif visibility == "audio":
                    audio_data = target.to_proximity_dict()
                    # Add directional audio hint without exact position
                    dx = target.position.x - viewer.position.x
                    dz = target.position.z - viewer.position.z
                    audio_data["direction"] = math.degrees(math.atan2(dx, dz))
                    audio_data["approx_distance"] = round(
                        viewer.position.distance_to(target.position) / 10
                    ) * 10  # Round to nearest 10
                    audio_players.append(audio_data)
                elif visibility == "minimal":
                    minimal_players.append(target.to_minimal_dict())
                # "none" - don't include at all

            # Get nearby loot (only within reasonable distance)
            nearby_loot = []
            for item_id, item in self.loot_items.items():
                if item.picked_up:
                    continue
                if viewer.position.distance_to(item.position) < 100:
                    nearby_loot.append({
                        "item_id": item.item_id,
                        "item_type": item.item_type,
                        "position": item.position.to_dict(),
                        "quantity": item.quantity,
                    })

            state = {
                "type": "game_state",
                "tick": self.current_tick,
                "server_time": current_time,
                "game_phase": self.game_phase.value,
                # Player's own authoritative state
                "self": {
                    "position": viewer.position.to_dict(),
                    "health": viewer.health,
                    "shield": viewer.shield,
                    "alive": viewer.alive,
                    "weapon": viewer.equipped_weapon,
                    "ammo": viewer.ammo,
                    "kills": viewer.kills,
                    "last_seq": viewer.last_input_seq,
                },
                # VISIBILITY-FILTERED other players
                "visible_players": visible_players,  # Full data - can see them
                "audio_players": audio_players,  # Nearby but not visible
                "known_players": minimal_players,  # Alive/dead status only
                # Counts for UI
                "players_alive": sum(1 for p in self.players.values() if p.alive),
                "total_players": len(self.players),
                # Nearby loot
                "loot": nearby_loot,
                # Zone info (public)
                "zone": {
                    "center": self.zone.get_current_center(current_time).to_dict(),
                    "radius": self.zone.get_current_radius(current_time),
                    "damage": self.zone.damage_per_tick,
                },
            }

            try:
                await viewer.websocket.send(json.dumps(state))
            except websockets.exceptions.ConnectionClosed:
                pass
            except Exception as e:
                print(f"[ERROR] Failed to send state to {viewer_id}: {e}")

    async def _broadcast(self, message: dict):
        """Broadcast a message to all connected players."""
        msg = json.dumps(message)
        disconnected = []
        for player_id, player in self.players.items():
            try:
                await player.websocket.send(msg)
            except:
                disconnected.append(player_id)

        for pid in disconnected:
            if pid in self.players:
                del self.players[pid]

    async def _broadcast_player_list(self):
        """Broadcast updated player list."""
        player_list = [
            {"player_id": p.player_id, "username": p.username, "alive": p.alive}
            for p in self.players.values()
        ]
        await self._broadcast({
            "type": "player_list",
            "players": player_list,
            "count": len(player_list),
        })

    def _log_event(self, event_type: str, data: dict):
        """Log a game event for replay/audit."""
        self.event_log.append({
            "time": time.time(),
            "tick": self.current_tick,
            "type": event_type,
            **data,
        })

    async def start(self):
        """Start the server."""
        print(f"[SERVER] Starting on {self.host}:{self.port}")
        print(f"[SERVER] Anti-Wallhack Protection: ACTIVE")
        print(f"[SERVER] - Server-side visibility determination")
        print(f"[SERVER] - Line-of-sight raycasting against {len(self.obstacles)} obstacles")
        print(f"[SERVER] - Position data ONLY sent for visible players")
        print(f"[SERVER] - Audio proximity hints for nearby non-visible players")
        print(f"[SERVER] Anti-Cheat: ACTIVE")
        print(f"[SERVER] - Server-authoritative movement validation")
        print(f"[SERVER] - Server-side hit detection")
        print(f"[SERVER] - Fire rate validation")
        print(f"[SERVER] - Speed/teleport detection")

        # Pre-generate some auth tokens for testing
        for i in range(10):
            token = self.generate_auth_token(f"TestPlayer{i}")
            print(f"[AUTH] Test token for TestPlayer{i}: {token[:16]}...")

        server = await websockets.serve(
            self.handle_connection,
            self.host,
            self.port,
            ping_interval=20,
            ping_timeout=10,
            max_size=2 ** 16,
        )

        # Start game loop
        game_task = asyncio.ensure_future(self.game_loop())

        print(f"[SERVER] Listening on ws://{self.host}:{self.port}")
        await server.wait_closed()


# Demo client for testing
async def demo_client(server_url: str, username: str):
    """Simple test client."""
    import random

    async with websockets.connect(server_url) as ws:
        # Authenticate
        await ws.send(json.dumps({
            "type": "auth",
            "username": username,
        }))

        welcome = json.loads(await ws.recv())
        print(f"[CLIENT {username}] Connected: {welcome.get('player_id')}")

        # Receive map data
        map_data = json.loads(await ws.recv())
        print(f"[CLIENT {username}] Received map with {len(map_data.get('obstacles', []))} obstacles")

        player_id = welcome["player_id"]

        async def send_inputs():
            x, z = 500.0, 500.0
            seq = 0
            while True:
                dx = random.uniform(-2, 2)
                dz = random.uniform(-2, 2)
                x += dx
                z += dz
                seq += 1
                await ws.send(json.dumps({
                    "type": "move",
                    "position": {"x": x, "y": 0, "z": z},
                    "rotation": random.uniform(0, 360),
                    "seq": seq,
                }))
                await asyncio.sleep(0.05)

        async def receive_state():
            while True:
                msg = json.loads(await ws.recv())
                if msg["type"] == "game_state":
                    visible = len(msg.get("visible_players", []))
                    audio = len(msg.get("audio_players", []))
                    known = len(msg.get("known_players", []))
                    alive = msg.get("players_alive", 0)
                    print(
                        f"[CLIENT {username}] Tick {msg['tick']}: "
                        f"visible={visible} audio={audio} known={known} "
                        f"alive={alive}"
                    )
                elif msg["type"] == "player_list":
                    print(f"[CLIENT {username}] Players: {msg['count']}")
                elif msg["type"] == "position_correction":
                    print(f"[CLIENT {username}] Position corrected: {msg.get('reason')}")

        await asyncio.gather(send_inputs(), receive_state())


async def main():
    """Main entry point."""
    import sys

    if len(sys.argv) > 1 and sys.argv[1] == "client":
        username = sys.argv[2] if len(sys.argv) > 2 else "TestClient"
        url = sys.argv[3] if len(sys.argv) > 3 else "ws://localhost:8765"
        await demo_client(url, username)
    else:
        server = BattleRoyaleServer()
        await server.start()


if __name__ == "__main__":
    asyncio.run(main())